48.query:
fetch spans
| filter k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"
| summarize span_count = count(), by:{trace.id}
| summarize traces = count(), by:{bin(span_count, 5)}

52.query:
timeseries {
  cpu = avg(dt.kubernetes.container.cpu_usage)
}, by:{k8s.namespace.name, k8s.workload.name}, filter:{k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"}

53.query:
timeseries {
  mem = avg(dt.kubernetes.container.memory_working_set)
}, by:{k8s.namespace.name, k8s.workload.name}, filter:{k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"}

54.query:
timeseries {
  cpu = avg(dt.kubernetes.container.cpu_usage)
}, by:{k8s.namespace.name, k8s.workload.name}, filter:{k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"}
| fieldsAdd avgCpu = arrayAvg(cpu)
| fields k8s.namespace.name, k8s.workload.name, avgCpu
| sort avgCpu desc
| limit 15

55.query:
timeseries {
  mem = avg(dt.kubernetes.container.memory_working_set)
}, by:{k8s.namespace.name, k8s.workload.name}, filter:{k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"}
| fieldsAdd avgMem = arrayAvg(mem)
| fields k8s.namespace.name, k8s.workload.name, avgMem
| sort avgMem desc
| limit 15

56.query:
timeseries {
  restarts = sum(dt.kubernetes.container.restarts)
}, by:{k8s.namespace.name, k8s.workload.name}, filter:{k8s.namespace.name == "utility-outage-analytics" or k8s.namespace.name == "utility-customer-billing"}
| fieldsAdd totalRestarts = arraySum(restarts)
| fields k8s.namespace.name, k8s.workload.name, totalRestarts
| filter totalRestarts > 0
| sort totalRestarts desc
